  final Uint8List rootHash;

  const SubtreeRoot({
    required this.completingBlockHeight,
    required this.rootHash,
  });

  @override
  int get hashCode => completingBlockHeight.hashCode ^ rootHash.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is SubtreeRoot &&
          runtimeType == other.runtimeType &&
          completingBlockHeight == other.completingBlockHeight &&
          rootHash == other.rootHash;
}

